const compressImage = (file, maxWidth, maxHeight, callback) => {
  if (!file) return;
  if (file.size > 800000) return alert("File too large. Please select an image under 800KB.");
  const reader = new FileReader();
  reader.onload = (e) => {
    const img = new Image();
    img.onload = () => {
      const cvs = document.createElement('canvas');
      let w = img.width, h = img.height;
      if (w > maxWidth) { h *= maxWidth / w; w = maxWidth; }
      if (h > maxHeight) { w *= maxHeight / h; h = maxHeight; }
      cvs.width = w; cvs.height = h;
      cvs.getContext('2d').drawImage(img, 0, 0, w, h);
      callback(cvs.toDataURL('image/jpeg', 0.8));
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(file);
};

function useTheme() {
  const [themeColor, setThemeColor] = useState(localStorage.getItem('themeColor') || '#8b9ced');
  useEffect(() => { localStorage.setItem('themeColor', themeColor); }, [themeColor]);
  return [themeColor, setThemeColor];
}

export default function App() {
  const [user, loading] = useAuthState(auth);
  const [themeColor, setThemeColor] = useTheme();
  const [showAuth, setShowAuth] = useState(false);

  const userRef = user ? firestore.collection('users').doc(user.uid) : null;
  const [userDoc] = useDocumentData(userRef);

  // QUOTA FIX: We only ping presence ONCE on load to save massive read/write costs.
  useEffect(() => {
    if (!user) return;
    if (userDoc && userDoc.banned) return;
    if (userRef) {
      userRef.set({ uid: user.uid, email: user.email || '', displayName: user.displayName || (user.email ? user.email.split('@')[0] : 'Anonymous'), photoURL: user.photoURL || DEFAULT_AVATAR, lastActive: Date.now() }, { merge: true });
    }
  }, [user]); // Removed interval to save Firebase Free Tier

  if (loading) return <div style={{background: '#313338', height: '100%'}}></div>;
  if (userDoc && userDoc.banned) return <div className="signin-container" style={{flexDirection: 'column', color: 'white'}}><h1 style={{color: '#da373c'}}>Banned</h1><button className="sign-in" onClick={() => auth.signOut()} style={{background:'#da373c'}}>Log Out</button></div>;
  if (showAuth && !user) return <AuthScreen themeColor={themeColor} goBack={() => setShowAuth(false)} />;

  return <MainApp themeColor={themeColor} setThemeColor={setThemeColor} isGuest={!user} onLoginClick={() => setShowAuth(true)} />;
}

function AuthScreen({ themeColor, goBack }) {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState(''); const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleAuth = async (e) => {
    e.preventDefault(); setError('');
    try { 
      if (isLogin) await auth.signInWithEmailAndPassword(email, password);
      else await auth.createUserWithEmailAndPassword(email, password);
    } catch (err) { setError(err.message); }
  };
  
  return (
    <div className="signin-container">
      <div className="modal-box" style={{width: '320px', alignItems: 'center'}}>
        <button onClick={goBack} style={{position:'absolute', top:10, left:10, background:'none', color:'#80848e', fontSize:20}}>←</button>
        <img src={DEFAULT_AVATAR} alt="logo" style={{width: 60}} />
        <h2 style={{margin: 0, color: '#fff'}}>{isLogin ? 'Welcome Back' : 'Create Account'}</h2>
        <form onSubmit={handleAuth} style={{display:'flex', flexDirection:'column', gap:16, width:'100%', padding:0, background:'none', marginTop: 10}}>
          <input type="email" placeholder="Email" value={email} onChange={e=>setEmail(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={e=>setPassword(e.target.value)} required />
          <button type="submit" className="sign-in" style={{background: themeColor}}>{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#da373c', fontSize: '13px', textAlign: 'center'}}>{error}</p>}
        <p style={{color: themeColor, fontSize: 13, cursor: 'pointer', margin:0}} onClick={() => setIsLogin(!isLogin)}>{isLogin ? 'Need an account?' : 'Have an account? Login'}</p>
        <button className="sign-in" style={{width:'100%', background:'#fff', color:'#000', marginTop: 10}} onClick={() => auth.signInWithPopup(new firebase.auth.GoogleAuthProvider())}>Google Login</button>
      </div>
    </div>
  );
}

